import json
entries = []

def T(code, test, lang):
    entries.append({"instruction": "Asagidaki fonksiyon icin unit test yaz:\n" + code, "response": test, "language": lang, "category": "test", "type": "manual", "format": "test"})

P="python";JS="javascript";JV="java";G="go"

def py_add(name, code, asserts):
    test = "def test_" + name + "():\n    " + "\n    ".join(asserts) + "\nimport pytest; pytest.main()"
    T(code, test, P)

def js_add(name, code, asserts):
    test = "function test_" + name + "(){\n  " + ";\n  ".join("console.assert(" + a + ")" for a in asserts) + ";\n}test_" + name + "();"
    T(code, test, JS)

def java_add(name, code, asserts):
    lines = ["        " + a + ";" for a in asserts]
    test = "import org.junit.*;\nimport static org.junit.Assert.*;\npublic class " + name + "Test {\n    @Test\n    public void test" + name + "() {\n" + "\n".join(lines) + "\n    }\n}"
    T(code, test, JV)

def go_add(name, code, asserts):
    test = "package main\nimport \"testing\"\nfunc Test" + name + "(t *testing.T) {\n    " + "\n    ".join(a + " { t.Fail() }" for a in asserts) + "\n}"
    T(code, test, G)

