# Sort/Search
py_add("bubble", "def bubble(arr):\n    n=len(arr)\n    for i in range(n):\n        for j in range(0,n-i-1):\n            if arr[j]>arr[j+1]: arr[j],arr[j+1]=arr[j+1],arr[j]\n    return arr", ["assert bubble([3,1,4,1,5])==[1,1,3,4,5]", "assert bubble([])==[]", "assert bubble([1])==[1]", "assert bubble([5,4,3,2,1])==[1,2,3,4,5]"])
py_add("quick", "def quick(arr):\n    if len(arr)<=1: return arr\n    p=arr[0]; l=[x for x in arr[1:] if x<=p]; r=[x for x in arr[1:] if x>p]\n    return quick(l)+[p]+quick(r)", ["assert quick([3,6,8,10,1,2,1])==[1,1,2,3,6,8,10]", "assert quick([])==[]", "assert quick([2])==[2]"])
py_add("merge", "def merge_s(arr):\n    if len(arr)<=1: return arr\n    m=len(arr)//2; return merge(merge_s(arr[:m]),merge_s(arr[m:]))\ndef merge(l,r):\n    res=[]; i=j=0\n    while i<len(l) and j<len(r):\n        if l[i]<=r[j]: res.append(l[i]); i+=1\n        else: res.append(r[j]); j+=1\n    return res+l[i:]+r[j:]", ["assert merge_s([38,27,43,3,9,82,10])==[3,9,10,27,38,43,82]", "assert merge_s([])==[]", "assert merge_s([1])==[1]"])
py_add("binary", "def bin_s(arr,t):\n    l,r=0,len(arr)-1\n    while l<=r:\n        m=(l+r)//2\n        if arr[m]==t: return m\n        if arr[m]<t: l=m+1\n        else: r=m-1\n    return -1", ["assert bin_s([1,3,5,7,9],5)==2", "assert bin_s([1,3,5,7,9],2)==-1", "assert bin_s([],1)==-1", "assert bin_s([5],5)==0"])
py_add("linear", "def lin_s(arr,t):\n    for i,v in enumerate(arr):\n        if v==t: return i\n    return -1", ["assert lin_s([4,2,7,1],7)==2", "assert lin_s([4,2,7,1],9)==-1", "assert lin_s([],1)==-1", "assert lin_s([1],1)==0"])
py_add("selection", "def sel_s(arr):\n    n=len(arr)\n    for i in range(n):\n        mi=i\n        for j in range(i+1,n):\n            if arr[j]<arr[mi]: mi=j\n        arr[i],arr[mi]=arr[mi],arr[i]\n    return arr", ["assert sel_s([64,25,12,22,11])==[11,12,22,25,64]", "assert sel_s([])==[]", "assert sel_s([3])==[3]"])
py_add("insertion", "def ins_s(arr):\n    for i in range(1,len(arr)):\n        key=arr[i]; j=i-1\n        while j>=0 and arr[j]>key:\n            arr[j+1]=arr[j]; j-=1\n        arr[j+1]=key\n    return arr", ["assert ins_s([12,11,13,5,6])==[5,6,11,12,13]", "assert ins_s([])==[]", "assert ins_s([1])==[1]"])
py_add("heap", "def heapify(arr,n,i):\n    l=i*2+1; r=i*2+2; lg=i\n    if l<n and arr[l]>arr[lg]: lg=l\n    if r<n and arr[r]>arr[lg]: lg=r\n    if lg!=i: arr[i],arr[lg]=arr[lg],arr[i]; heapify(arr,n,lg)\ndef heap_s(arr):\n    n=len(arr)\n    for i in range(n//2-1,-1,-1): heapify(arr,n,i)\n    for i in range(n-1,0,-1): arr[i],arr[0]=arr[0],arr[i]; heapify(arr,i,0)\n    return arr", ["assert heap_s([4,10,3,5,1])==[1,3,4,5,10]", "assert heap_s([])==[]", "assert heap_s([2,1])==[1,2]"])
py_add("counting", "def cnt_s(arr):\n    if not arr: return arr\n    mx=max(arr); c=[0]*(mx+1)\n    for x in arr: c[x]+=1\n    r=[]\n    for i,n in enumerate(c): r.extend([i]*n)\n    return r", ["assert cnt_s([4,2,2,8,3,3,1])==[1,2,2,3,3,4,8]", "assert cnt_s([])==[]", "assert cnt_s([1])==[1]"])

# Data Structures
py_add("stack", "class Stack:\n    def __init__(s): s.items=[]\n    def push(s,i): s.items.append(i)\n    def pop(s):\n        if s.is_empty(): raise IndexError('Bos')\n        return s.items.pop()\n    def peek(s): return s.items[-1]\n    def is_empty(s): return len(s.items)==0\n    def size(s): return len(s.items)", ["s=Stack()\nassert s.is_empty()==True\ns.push(1);s.push(2);s.push(3)\nassert s.pop()==3\nassert s.peek()==2\nassert s.size()==2\nimport pytest\nwith pytest.raises(IndexError): Stack().pop()"])
py_add("queue", "class Queue:\n    def __init__(s): s.items=[]\n    def enq(s,i): s.items.append(i)\n    def deq(s):\n        if s.is_empty(): raise IndexError('Bos')\n        return s.items.pop(0)\n    def front(s): return s.items[0]\n    def is_empty(s): return len(s.items)==0\n    def size(s): return len(s.items)", ["q=Queue()\nq.enq(1);q.enq(2);q.enq(3)\nassert q.deq()==1\nassert q.front()==2\nassert q.size()==2\nimport pytest\nwith pytest.raises(IndexError): Queue().deq()"])
py_add("linked", "class Node:\n    def __init__(s,d): s.data=d; s.next=None\nclass LinkedList:\n    def __init__(s): s.head=None\n    def append(s,d):\n        if not s.head: s.head=Node(d); return\n        c=s.head\n        while c.next: c=c.next\n        c.next=Node(d)\n    def to_list(s):\n        r=[]; c=s.head\n        while c: r.append(c.data); c=c.next\n        return r", ["ll=LinkedList()\nassert ll.to_list()==[]\nll.append(1);ll.append(2);ll.append(3)\nassert ll.to_list()==[1,2,3]"])
py_add("bst", "class TreeNode:\n    def __init__(s,v): s.val=v; s.left=s.right=None\nclass BST:\n    def __init__(s): s.root=None\n    def insert(s,v):\n        if not s.root: s.root=TreeNode(v); return\n        s._insert(s.root,v)\n    def _insert(s,n,v):\n        if v<n.val:\n            if n.left: s._insert(n.left,v)\n            else: n.left=TreeNode(v)\n        else:\n            if n.right: s._insert(n.right,v)\n            else: n.right=TreeNode(v)\n    def search(s,v): return s._search(s.root,v)\n    def _search(s,n,v):\n        if not n: return False\n        if n.val==v: return True\n        return s._search(n.left,v) if v<n.val else s._search(n.right,v)", ["bst=BST()\nbst.insert(5);bst.insert(3);bst.insert(7)\nassert bst.search(5)==True\nassert bst.search(3)==True\nassert bst.search(9)==False\nassert BST().search(1)==False"])
py_add("bfs", "def bfs(graph,start):\n    v=set(); q=[start]; r=[]\n    while q:\n        n=q.pop(0)\n        if n not in v: v.add(n); r.append(n); q.extend(graph[n])\n    return r", ["g={\"A\":[\"B\",\"C\"],\"B\":[\"D\"],\"C\":[\"E\"],\"D\":[],\"E\":[]}\nassert bfs(g,\"A\")==[\"A\",\"B\",\"C\",\"D\",\"E\"]\nassert bfs({\"X\":[]},\"X\")==[\"X\"]"])
py_add("dfs", "def dfs(graph,start):\n    v=set(); r=[]\n    def _dfs(n):\n        v.add(n); r.append(n)\n        for nb in graph[n]:\n            if nb not in v: _dfs(nb)\n    _dfs(start)\n    return r", ["g={\"A\":[\"B\",\"C\"],\"B\":[\"D\"],\"C\":[\"E\"],\"D\":[],\"E\":[]}\nassert dfs(g,\"A\")==[\"A\",\"B\",\"D\",\"C\",\"E\"]\nassert dfs({\"X\":[]},\"X\")==[\"X\"]"])
py_add("dijkstra", "import heapq\ndef dijkstra(graph,start):\n    d={n:float('inf') for n in graph}\n    d[start]=0; pq=[(0,start)]\n    while pq:\n        cd,c=heapq.heappop(pq)\n        if cd>d[c]: continue\n        for nb,w in graph[c].items():\n            nd=cd+w\n            if nd<d[nb]: d[nb]=nd; heapq.heappush(pq,(nd,nb))\n    return d", ["g={\"A\":{\"B\":1,\"C\":4},\"B\":{\"C\":2,\"D\":5},\"C\":{\"D\":1},\"D\":{}}\nd=dijkstra(g,\"A\")\nassert d[\"A\"]==0 and d[\"B\"]==1 and d[\"C\"]==3 and d[\"D\"]==4"])
py_add("knap", "def knap(W,wt,val,n):\n    dp=[[0]*(W+1) for _ in range(n+1)]\n    for i in range(1,n+1):\n        for w in range(1,W+1):\n            if wt[i-1]<=w: dp[i][w]=max(val[i-1]+dp[i-1][w-wt[i-1]],dp[i-1][w])\n            else: dp[i][w]=dp[i-1][w]\n    return dp[n][W]", ["val=[60,100,120]; wt=[10,20,30]\nassert knap(50,wt,val,3)==220\nassert knap(0,[1],[5],1)==0"])
py_add("edit_dist", "def edit_dist(s1,s2):\n    m,n=len(s1),len(s2); dp=[[0]*(n+1) for _ in range(m+1)]\n    for i in range(m+1): dp[i][0]=i\n    for j in range(n+1): dp[0][j]=j\n    for i in range(1,m+1):\n        for j in range(1,n+1):\n            if s1[i-1]==s2[j-1]: dp[i][j]=dp[i-1][j-1]\n            else: dp[i][j]=1+min(dp[i-1][j],dp[i][j-1],dp[i-1][j-1])\n    return dp[m][n]", ["assert edit_dist('kitten','sitting')==3", "assert edit_dist('','abc')==3", "assert edit_dist('same','same')==0"])
py_add("lcs", "def lcs(X,Y):\n    m,n=len(X),len(Y); dp=[[0]*(n+1) for _ in range(m+1)]\n    for i in range(1,m+1):\n        for j in range(1,n+1):\n            if X[i-1]==Y[j-1]: dp[i][j]=dp[i-1][j-1]+1\n            else: dp[i][j]=max(dp[i-1][j],dp[i][j-1])\n    return dp[m][n]", ["assert lcs('AGGTAB','GXTXAYB')==4", "assert lcs('ABC','DEF')==0", "assert lcs('','ABC')==0"])
