py_add("cc", "def valid_cc(num):\n    num=num.replace(' ','')\n    if not num.isdigit() or len(num)!=16: return False\n    t=0\n    for i,d in enumerate(reversed(num)):\n        n=int(d)\n        if i%2==1: n*=2\n        if n>9: n-=9\n        t+=n\n    return t%10==0", ["assert valid_cc('4532015112830366')==True", "assert valid_cc('1234567812345678')==False", "assert valid_cc('abcd')==False"])
