py_add("retry", "import time\ndef retry(fn,mr=3,d=0.1):\n    for i in range(mr):\n        try: return fn()\n        except:\n            if i==mr-1: raise\n            time.sleep(d)", ["from unittest.mock import Mock\nfn=Mock(side_effect=[ValueError,ValueError,'success'])\nassert retry(fn,mr=3,d=0.01)=='success'\nassert fn.call_count==3"])
py_add("rate", "class RateLimiter:\n    def __init__(s,mc,p): s.max_calls=mc; s.period=p; s.calls=[]\n    def allow(s):\n        import time; n=time.time()\n        s.calls=[c for c in s.calls if n-c<s.period]\n        if len(s.calls)>=s.max_calls: return False\n        s.calls.append(n); return True", ["rl=RateLimiter(2,10)\nassert rl.allow()==True and rl.allow()==True and rl.allow()==False"])
py_add("lru", "class LRUCache:\n    def __init__(s,cap): s.cap=cap; s.cache={}; s.order=[]\n    def get(s,k):\n        if k in s.cache: s.order.remove(k); s.order.append(k); return s.cache[k]\n        return -1\n    def put(s,k,v):\n        if k in s.cache: s.order.remove(k)\n        elif len(s.cache)>=s.cap: o=s.order.pop(0); del s.cache[o]\n        s.cache[k]=v; s.order.append(k)", ["c=LRUCache(2)\nc.put(1,1);c.put(2,2)\nassert c.get(1)==1\nc.put(3,3); assert c.get(2)==-1\nc.put(4,4); assert c.get(1)==-1; assert c.get(3)==3"])
py_add("mat_mul", "def mat_mul(A,B):\n    n=len(A); m=len(A[0]); p=len(B[0])\n    r=[[0]*p for _ in range(n)]\n    for i in range(n):\n        for j in range(p):\n            for k in range(m): r[i][j]+=A[i][k]*B[k][j]\n    return r", ["A=[[1,2],[3,4]]; B=[[5,6],[7,8]]\nassert mat_mul(A,B)==[[19,22],[43,50]]\nassert mat_mul([[1,2,3]],[[4],[5],[6]])==[[32]]"])
