py_add("vec_add", "def vec_add(v1,v2): return [a+b for a,b in zip(v1,v2)]", ["assert vec_add([1,2],[3,4])==[4,6]", "assert vec_add([-1,0],[1,0])==[0,0]", "assert vec_add([],[])==[]"])
