py_add("d_comp", "def d_comp(a,b):\n    if type(a)!=type(b): return False\n    if isinstance(a,dict): return a.keys()==b.keys() and all(d_comp(a[k],b[k]) for k in a)\n    if isinstance(a,(list,tuple)): return len(a)==len(b) and all(d_comp(x,y) for x,y in zip(a,b))\n    return a==b", ["assert d_comp({'a':[1,2]},{'a':[1,2]})==True", "assert d_comp({'a':[1,2]},{'a':[1,3]})==False", "assert d_comp([1,2],[1,2])==True", "assert d_comp('abc','abc')==True"])
py_add("once_f", "def once(fn):\n    called=False; r=None\n    def w(*a,**kw):\n        nonlocal called,r\n        if not called: r=fn(*a,**kw); called=True\n        return r\n    return w", ["cc=0\n@once\ndef c(): nonlocal cc; cc+=1; return 42\nassert c()==42 and c()==42 and cc==1"])
py_add("pipe", "def pipe(*fns):\n    def apply(x):\n        for fn in fns: x=fn(x)\n        return x\n    return apply", ["f=pipe(lambda x:x+1,lambda x:x*2)\nassert f(5)==12 and f(0)==2\nassert pipe()(5)==5"])
py_add("compose", "def compose(*fns):\n    def apply(x):\n        for fn in reversed(fns): x=fn(x)\n        return x\n    return apply", ["f=compose(lambda x:x+1,lambda x:x*2)\nassert f(5)==11\nassert compose()(5)==5"])
py_add("curry", "def curry(fn):\n    def c(*a):\n        if len(a)>=fn.__code__.co_argcount: return fn(*a)\n        return lambda *m: c(*a,*m)\n    return c", ["@curry\ndef add(a,b,c): return a+b+c\nassert add(1)(2)(3)==6\nassert add(1,2)(3)==6\nassert add(1,2,3)==6"])
