py_add("to_bin", "def to_bin(n):\n    if n==0: return '0'\n    r=''\n    while n>0: r=str(n%2)+r; n//=2\n    return r", ["assert to_bin(0)=='0' and to_bin(5)=='101'", "assert to_bin(255)=='11111111' and to_bin(1)=='1'"])
py_add("from_bin", "def from_bin(b): return int(b,2)", ["assert from_bin('101')==5 and from_bin('0')==0", "assert from_bin('11111111')==255"])
py_add("caesar", "def caesar(text,shift):\n    r=[]\n    for c in text:\n        if c.isalpha():\n            base=ord('a') if c.islower() else ord('A')\n            r.append(chr((ord(c)-base+shift)%26+base))\n        else: r.append(c)\n    return ''.join(r)", ["assert caesar('abc',1)=='bcd'", "assert caesar('xyz',3)=='abc'", "assert caesar('Test',0)=='Test'", "assert caesar('123',5)=='123'"])
py_add("bal", "def bal_paren(s):\n    st=[]; p={')':'(',']':'[','}':'{'}\n    for c in s:\n        if c in '([{': st.append(c)\n        elif c in ')]}':\n            if not st or st.pop()!=p[c]: return False\n    return len(st)==0", ["assert bal_paren('()[]{}')==True", "assert bal_paren('([)]')==False", "assert bal_paren('(')==False", "assert bal_paren('')==True"])
py_add("kmp", "def kmp(text,pat):\n    n,m=len(text),len(pat)\n    if m==0: return 0\n    lps=[0]*m; j=0\n    for i in range(1,m):\n        while j>0 and pat[i]!=pat[j]: j=lps[j-1]\n        if pat[i]==pat[j]: j+=1; lps[i]=j\n    j=0\n    for i in range(n):\n        while j>0 and text[i]!=pat[j]: j=lps[j-1]\n        if text[i]==pat[j]: j+=1\n        if j==m: return i-m+1\n    return -1", ["assert kmp('ABABDABACDABABCABAB','ABABCABAB')==10", "assert kmp('hello','ll')==2", "assert kmp('hello','x')==-1"])
py_add("rk", "def rk(text,pat):\n    n,m=len(text),len(pat)\n    if m==0: return 0\n    d,q=256,101; h=pow(d,m-1,q); p=t=0\n    for i in range(m): p=(d*p+ord(pat[i]))%q; t=(d*t+ord(text[i]))%q\n    for i in range(n-m+1):\n        if p==t and text[i:i+m]==pat: return i\n        if i<n-m: t=(d*(t-ord(text[i])*h)+ord(text[i+m]))%q\n    return -1", ["assert rk('2359023141526739921','31415')==6", "assert rk('hello','ll')==2", "assert rk('test','x')==-1"])
py_add("lps", "def lps(s):\n    n=len(s)\n    if n<2: return s\n    st,mx=0,1\n    for i in range(n):\n        for l,r in[(i,i),(i,i+1)]:\n            while l>=0 and r<n and s[l]==s[r]:\n                if r-l+1>mx: st,mx=l,r-l+1\n                l-=1; r+=1\n    return s[st:st+mx]", ["assert lps('babad') in ['bab','aba']", "assert lps('cbbd')=='bb'", "assert lps('a')=='a'", "assert lps('')==''"])
py_add("lcp", "def lcp(strs):\n    if not strs: return ''\n    p=strs[0]\n    for s in strs[1:]:\n        while not s.startswith(p):\n            p=p[:-1]\n            if not p: return ''\n    return p", ["assert lcp(['flower','flow','flight'])=='fl'", "assert lcp(['dog','racecar','car'])==''", "assert lcp([])==''", "assert lcp(['alone'])=='alone'"])
