py_add("isbn", "def valid_isbn(isbn):\n    d=isbn.replace('-','').replace(' ','')\n    if len(d)!=10: return False\n    t=0\n    for i,ch in enumerate(d):\n        if ch=='X' and i==9: t+=10*(10-i)\n        elif ch.isdigit(): t+=int(ch)*(10-i)\n        else: return False\n    return t%11==0", ["assert valid_isbn('0-306-40615-2')==True", "assert valid_isbn('0306406152')==True", "assert valid_isbn('1234567890')==False"])
