py_add("throttle_f", "import time\ndef throttle(fn,interval):\n    last=0\n    def w(*a,**kw):\n        nonlocal last\n        n=time.time()\n        if n-last>=interval: last=n; return fn(*a,**kw)\n    return w", ["from unittest.mock import Mock\nm=Mock(); fn=throttle(m,0.1)\nfn();fn();fn()\nassert m.call_count in [1,2]"])
py_add("debounce_f", "import time\ndef debounce(fn,delay):\n    last=0\n    def w(*a,**kw):\n        nonlocal last; last=time.time()\n        def call():\n            if time.time()-last>=delay: return fn(*a,**kw)\n        return call\n    return w", ["from unittest.mock import Mock\nm=Mock(); fn=debounce(m,0.05)\nfn(); import time; time.sleep(0.1)\nassert m.called"])
py_add("cb", "class CircularBuffer:\n    def __init__(s,sz): s.size=sz; s.buf=[None]*sz; s.pos=0; s.cnt=0\n    def write(s,v):\n        s.buf[s.pos]=v; s.pos=(s.pos+1)%s.size; s.cnt=min(s.cnt+1,s.size)\n    def read_all(s):\n        if s.cnt==0: return []\n        st=(s.pos-s.cnt)%s.size\n        return [s.buf[(st+i)%s.size] for i in range(s.cnt)]", ["cb=CircularBuffer(3)\nassert cb.read_all()==[]\ncb.write(1);cb.write(2);cb.write(3)\nassert cb.read_all()==[1,2,3]\ncb.write(4); assert cb.read_all()==[2,3,4]"])
py_add("deque", "class Deque:\n    def __init__(s): s.items=[]\n    def add_front(s,i): s.items.insert(0,i)\n    def add_rear(s,i): s.items.append(i)\n    def remove_front(s): return s.items.pop(0)\n    def remove_rear(s): return s.items.pop()\n    def is_empty(s): return len(s.items)==0", ["d=Deque()\nassert d.is_empty()==True\nd.add_front(1);d.add_rear(2);d.add_front(3)\nassert d.remove_front()==3 and d.remove_rear()==2 and d.size()==1"])
py_add("pq", "import heapq\nclass PriorityQueue:\n    def __init__(s): s.heap=[]\n    def push(s,i,p): heapq.heappush(s.heap,(p,i))\n    def pop(s): return heapq.heappop(s.heap)[1]\n    def is_empty(s): return len(s.heap)==0", ["pq=PriorityQueue()\npq.push('low',5);pq.push('high',1);pq.push('mid',3)\nassert pq.pop()=='high' and pq.pop()=='mid' and pq.pop()=='low'"])
