py_add("flatten_dict", "def flatten_dict(d,parent='',sep='.'):\n    items=[]\n    for k,v in d.items():\n        nk=f'{parent}{sep}{k}' if parent else k\n        if isinstance(v,dict): items.extend(flatten_dict(v,nk,sep).items())\n        else: items.append((nk,v))\n    return dict(items)", ["r=flatten_dict({'a':{'b':1,'c':2},'d':3})\nassert r=={'a.b':1,'a.c':2,'d':3}"])
