js_add("lru", "class LRU{constructor(c){this.cap=c;this.cache=new Map()}get(k){if(!this.cache.has(k))return-1;const v=this.cache.get(k);this.cache.delete(k);this.cache.set(k,v);return v}put(k,v){if(this.cache.has(k))this.cache.delete(k);else if(this.cache.size>=this.cap){const o=this.cache.keys().next().value;this.cache.delete(o)}this.cache.set(k,v)}}", ["(c=>{c.put(1,1);c.put(2,2);c.put(3,3);return c.get(1)===-1})(new LRU(2))"])
