def java_add(name, code, asserts):
    lines = ["        " + a + ";" for a in asserts]
    test = "import org.junit.*;\nimport static org.junit.Assert.*;\npublic class " + name + "Test {\n    @Test\n    public void test" + name + "() {\n" + "\n".join(lines) + "\n    }\n}"
    T(code, test, JV)

