py_add("matrix_add", "def mat_add(A,B):\n    n=len(A); m=len(A[0])\n    return [[A[i][j]+B[i][j] for j in range(m)] for i in range(n)]", ["assert mat_add([[1,2],[3,4]],[[5,6],[7,8]])==[[6,8],[10,12]]"])
py_add("spiral", "def spiral(n):\n    m=[[0]*n for _ in range(n)]\n    t,b,l,r=0,n-1,0,n-1; d=1\n    while t<=b and l<=r:\n        for i in range(l,r+1): m[t][i]=d; d+=1\n        t+=1\n        for i in range(t,b+1): m[i][r]=d; d+=1\n        r-=1\n        for i in range(r,l-1,-1): m[b][i]=d; d+=1\n        b-=1\n        for i in range(b,t-1,-1): m[i][l]=d; d+=1\n        l+=1\n    return m", ["r=spiral(3); assert r[0][0]==1 and r[0][2]==3 and r[2][0]==7"])
py_add("powerset", "def powerset(arr):\n    r=[[]]\n    for e in arr:\n        r+=[x+[e] for x in r]\n    return r", ["assert len(powerset([1,2,3]))==8", "assert [] in powerset([1,2])"])
py_add("permute", "def permute(arr):\n    if len(arr)<=1: return [arr]\n    r=[]\n    for i,e in enumerate(arr):\n        for p in permute(arr[:i]+arr[i+1:]):\n            r.append([e]+p)\n    return r", ["assert len(permute([1,2,3]))==6"])
