java_add("Chunk", "public class ArrayUtils { public static int[][] chunk(int[] a,int s){int n=(int)Math.ceil((double)a.length/s);int[][] r=new int[n][];for(int i=0;i<n;i++)r[i]=java.util.Arrays.copyOfRange(a,i*s,Math.min((i+1)*s,a.length));return r;} }", ["assertArrayEquals(new int[]{1,2,3},ArrayUtils.chunk(new int[]{1,2,3,4,5},3)[0])"])
java_add("Flatten2D", "public class ArrayUtils { public static int[] flatten(int[][] a){return java.util.Arrays.stream(a).flatMapToInt(java.util.Arrays::stream).toArray();} }", ["assertArrayEquals(new int[]{1,2,3,4},ArrayUtils.flatten(new int[][]{{1,2},{3,4}}))"])
java_add("Intersection2", "public class ArrayUtils { public static int[] intersection(int[] a,int[] b){return java.util.Arrays.stream(a).filter(x->java.util.Arrays.binarySearch(b,x)>=0).distinct().toArray();} }", ["assertArrayEquals(new int[]{2,3},ArrayUtils.intersection(new int[]{1,2,3},new int[]{2,3,4}))"])
java_add("Union2", "public class ArrayUtils { public static int[] union(int[] a,int[] b){return java.util.Arrays.stream(java.util.stream.IntStream.concat(java.util.Arrays.stream(a),java.util.Arrays.stream(b)).distinct().toArray()).sorted().toArray();} }", ["assertArrayEquals(new int[]{1,2,3},ArrayUtils.union(new int[]{1,2},new int[]{2,3}))"])
java_add("H2R", "public class ColorUtils { public static int[] hexToRgb(String h){h=h.replace(\"#\",\"\");return new int[]{Integer.parseInt(h.substring(0,2),16),Integer.parseInt(h.substring(2,4),16),Integer.parseInt(h.substring(4,6),16)};} }", ["assertArrayEquals(new int[]{255,0,0},ColorUtils.hexToRgb(\"#FF0000\"))"])
java_add("R2H", "public class ColorUtils { public static String rgbToHex(int r,int g,int b){return String.format(\"#%02x%02x%02x\",r,g,b);} }", ["assertEquals(\"#ff0000\",ColorUtils.rgbToHex(255,0,0))"])
java_add("KV", "public class StringUtils { public static int countV(String s){return s.replaceAll(\"(?i)[^aeiou]\",\"\").length();} }", ["assertEquals(3,StringUtils.countV(\"merhaba\"))","assertEquals(0,StringUtils.countV(\"xyz\"))"])
java_add("KW", "public class StringUtils { public static int countW(String s){if(s.trim().isEmpty())return 0;return s.trim().split(\"\\\\s+\").length;} }", ["assertEquals(2,StringUtils.countW(\"merhaba dunya\"))","assertEquals(0,StringUtils.countW(\"\"))"])
java_add("TTime", "public class StringUtils { public static boolean validTime(String t){return t.matches(\"^([01]\\\\d|2[0-3]):[0-5]\\\\d(:[0-5]\\\\d)?$\");} }", ["assertTrue(StringUtils.validTime(\"14:30\"))","assertFalse(StringUtils.validTime(\"25:00\"))"])

# Go +5
go_add("Sort", "func isSorted(arr []int) bool { for i:=0;i<len(arr)-1;i++{ if arr[i]>arr[i+1]{return false} }; return true }", ["if !isSorted([]int{1,2,3,4})","if isSorted([]int{1,3,2})"])
go_add("Pal2", "func isPalindrome(s string) bool { r:=[]rune(s); for i,j:=0,len(r)-1;i<j;i,j=i+1,j-1{ if r[i]!=r[j]{return false} }; return true }", ["if !isPalindrome(\"kek\")","if isPalindrome(\"abc\")"])
go_add("Longest", "func longestWord(t string) string { w:=strings.Fields(t); r:=\"\"; for _,x:=range w{ if len(x)>len(r){ r=x } }; return r }", ["if longestWord(\"merhaba dunya\")!=\"merhaba\""])
go_add("IsInt", "func isValidInteger(s string) bool { _,err:=strconv.Atoi(s); return err==nil }", ["if !isValidInteger(\"123\")","if isValidInteger(\"abc\")"])
go_add("StrLen", "func stringLen(s string) int { return len([]rune(s)) }", ["if stringLen(\"merhaba\")!=7"])

